  function findById(list,id){
    for(var i=0;i<list.length;i++){if(list[i]&&list[i].id===id)return list[i];}
    return null;
  }
  function findLesson(module,lessonNumber){
    var lessons=module&&module.lessons;
    if(!Array.isArray(lessons))return null;
    for(var i=0;i<lessons.length;i++){if(lessons[i]&&lessons[i].n===lessonNumber)return lessons[i];}
    return null;
  }
  function alreadyWired(gallery,imageUrl){
    for(var i=0;i<gallery.length;i++){if(gallery[i]&&gallery[i].imageUrl===imageUrl)return true;}
    return false;
  }
  function quiz(q,opts,correct,explain){
    return {q:q,opts:opts,correct:correct,explain:explain};
  }
  function richHomeworkSpec(brief,deliverables,steps,checklist,proofRequired,reflection,reviewGate){
    return {
      brief:brief,
      deliverables:deliverables,
      steps:steps,
      checklist:checklist,
      proofRequired:proofRequired,
      reflection:reflection,
      reviewGate:reviewGate
    };
  }
