  function homework(deliverable,qualityBar,timeEstimate,submit){
    var hw={deliverable:deliverable,qualityBar:qualityBar,timeEstimate:timeEstimate,submit:submit};
    var rich=RICH_HOMEWORK_BY_DELIVERABLE[deliverable];
    if(rich){
      Object.keys(rich).forEach(function(key){hw[key]=rich[key];});
    }
    return hw;
  }
  function lessonRewrite(coreIdea,whyItMatters,mistakeToAvoid,example,lab,quizzes,hw){
    return {
      learnCards:{coreIdea:coreIdea,whyItMatters:whyItMatters,mistakeToAvoid:mistakeToAvoid},
      examples:[example],
      lab:lab,
      quiz:quizzes,
      homework:hw
    };
  }
