	  function standardRewrite(rule,reason,mistake,example,starter,constraint,success,failure,q1,o1,c1,e1,q2,o2,c2,e2,deliverable,qualityBar,timeEstimate,submit){
	    return lessonRewrite(
	      'Rule: '+rule,
	      'Reason: '+reason,
	      'Mistake: '+mistake,
	      'Worked example: '+example,
	      'Starter input: '+starter+' Constraint: '+constraint+' Success criteria: '+success+' Failure mode: '+failure,
	      [quiz(q1,o1,c1,e1),quiz(q2,o2,c2,e2)],
	      homework(deliverable,qualityBar,timeEstimate,submit)
	    );
	  }
