  function applyCourseContentLogic(modules){
    if(!Array.isArray(modules))return modules;
    Object.keys(COURSE_CONTENT_HOMEWORK_REWRITES).forEach(function(id){
      var module=findById(modules,id),rewrites=COURSE_CONTENT_HOMEWORK_REWRITES[id];
      if(!module||!Array.isArray(module.lessons))return;
      Object.keys(rewrites).forEach(function(lessonNumber){
        var lesson=findLesson(module,parseInt(lessonNumber,10)),patch=rewrites[lessonNumber];
        if(!lesson||!patch)return;
        lesson.homework=Object.assign({},lesson.homework||{},patch);
      });
    });
    return modules;
  }
		  function rewritePriorityContent(modules){
	    if(!Array.isArray(modules))return modules;
	    var allRewrites=Object.assign({},PRIORITY_CONTENT_REWRITES,REMAINING_CONTENT_REWRITES);
	    Object.keys(allRewrites).forEach(function(id){
	      var module=findById(modules,id),rewrites=allRewrites[id];
      if(!module||!Array.isArray(module.lessons))return;
      Object.keys(rewrites).forEach(function(lessonNumber){
        var lesson=findLesson(module,parseInt(lessonNumber,10)),rewrite=rewrites[lessonNumber];
        if(!lesson||!rewrite)return;
        lesson.learnCards=rewrite.learnCards;
        lesson.examples=rewrite.examples;
        lesson.lab=rewrite.lab;
        lesson.quiz=rewrite.quiz;
        lesson.homework=rewrite.homework;
      });
    });
    return modules;
  }
  function wireSpecimenGalleries(modules){
    if(!Array.isArray(modules))return modules;
    Object.keys(SPECIMEN_GALLERIES).forEach(function(id){
      var specs=Array.isArray(SPECIMEN_GALLERIES[id])?SPECIMEN_GALLERIES[id]:[SPECIMEN_GALLERIES[id]];
      var module=findById(modules,id);
      specs.forEach(function(spec){
        var lesson=findLesson(module,spec.lesson);
        if(!lesson)return;
        if(!Array.isArray(lesson.gallery))lesson.gallery=[];
        spec.items.slice().reverse().forEach(function(item){
          if(!alreadyWired(lesson.gallery,item.imageUrl))lesson.gallery.unshift(item);
        });
      });
    });
    return modules;
  }
  function cleanSentence(text,fallback){
    text=String(text||'').replace(/^(Rule|Reason|Mistake|Worked example|Starter input|Constraint|Success criteria|Failure mode):\s*/i,'').trim();
    if(!text)return fallback||'';
    return text.charAt(0).toUpperCase()+text.slice(1);
  }
  function lessonLabParts(lab){
    lab=String(lab||'');
    function between(label,nextLabels){
      var start=lab.toLowerCase().indexOf(label.toLowerCase()+':');
      if(start<0)return '';
      start+=label.length+1;
      var end=lab.length;
      nextLabels.forEach(function(n){
        var idx=lab.toLowerCase().indexOf(n.toLowerCase()+':',start);
        if(idx>-1&&idx<end)end=idx;
      });
      return cleanSentence(lab.slice(start,end).trim());
    }
    return {
      starter:between('Starter input',['Constraint','Success criteria','Failure mode']),
      constraint:between('Constraint',['Success criteria','Failure mode']),
      success:between('Success criteria',['Failure mode']),
      failure:between('Failure mode',[])
    };
  }
  function moduleHeroCard(module){
    var slug=(module&&module.heroSlug)||((module&&module.id)||'image-prompting-foundations');
    return 'assets/module-heroes/'+slug+'-card.jpg';
  }
  function moduleContentMode(module){
    var track=module&&module.track;
    if(track==='video')return {kind:'video specimen',artifact:'clip proof board',input:'shot prompt',output:'clip/keyframe proof',decision:'motion, pacing, or export decision'};
    if(track==='automation'||track==='operations')return {kind:'workflow receipt',artifact:'workflow proof board',input:'source input',output:'run log or approval proof',decision:'automation boundary'};
    if(track==='claude')return {kind:'workbench specimen',artifact:'Claude workbench artifact',input:'source context',output:'Claude output',decision:'review and revision decision'};
    if(track==='research')return {kind:'research receipt',artifact:'source-backed research pack',input:'research question',output:'claim/source table',decision:'verification decision'};
    if(track==='foundations')return {kind:'starter specimen',artifact:'AI starter artifact',input:'real task',output:'usable AI output',decision:'tool and prompt decision'};
    if(track==='signature')return {kind:'case specimen',artifact:'concept production board',input:'concept brief',output:'first-frame/story proof',decision:'concept spine decision'};
    return {kind:'image specimen',artifact:'prompt-output board',input:'prompt or reference',output:'generated result',decision:'visual control decision'};
  }
  function lessonSpecimen(module,lesson){
    var mode=moduleContentMode(module),parts=lessonLabParts(lesson&&lesson.lab),cards=(lesson&&lesson.learnCards)||{};
    var examples=Array.isArray(lesson&&lesson.examples)?lesson.examples:[];
    var rule=cleanSentence(cards.coreIdea||lesson.studentOutcome||lesson.title||module.title,'Study the session decision rule.');
    var prompt=examples[0]||('Specimen: start from '+(parts.starter||mode.input)+' and apply the rule: '+rule);
    var tool=(Array.isArray(module&&module.tools)&&module.tools.length?module.tools.slice(0,2).join(' + '):'AI workflow');
    return {
      prompt:prompt,
      tool:tool,
      imageUrl:moduleHeroCard(module),
      descResult:'Use this '+mode.kind+' to identify the '+mode.input+', the controlled '+mode.decision+', the visible '+mode.output+', and the failure mode before opening Lab.'
    };
  }
  function ensureLessonSpecimens(modules){
    modules.forEach(function(module){
      (module.lessons||[]).forEach(function(lesson){
        if(!Array.isArray(lesson.gallery))lesson.gallery=[];
        var hasReal=lesson.gallery.some(function(item){return item&&item.imageUrl;});
        if(!hasReal)lesson.gallery.unshift(lessonSpecimen(module,lesson));
      });
    });
    return modules;
  }
  function homeworkProfile(module){
    var track=module&&module.track;
    if(track==='video')return {
      name:'video proof pack',
      make:'Build one shot board, clip test, or export pack that proves the session decision in motion.',
      proof:'Shot prompt, storyboard/keyframe, clip link or screenshot, and a note naming the motion or pacing decision.',
      reflection:'Which motion, story, audio, or export decision changed the result most?',
      reject:'Reject if the clip looks polished but the prompt, timing, failure diagnosis, or export proof is missing.'
    };
    if(track==='automation'||track==='operations')return {
      name:'workflow receipt',
      make:'Build a safe workflow proof with input, AI step, approval gate, output, and recovery note.',
      proof:'Workflow diagram or screenshot, source input, AI draft/output, approval gate, run log, and failure path.',
      reflection:'Where must the human approve before the workflow is allowed to act?',
      reject:'Reject if the workflow skips approval, hides the source input, or cannot prove what ran.'
    };
    if(track==='claude')return {
      name:'Claude workbench artifact',
      make:'Build a Claude output that starts from real context and ends with a reviewed, reusable artifact.',
      proof:'Source context, Claude prompt/instruction, first output, revision note, final artifact, and review decision.',
      reflection:'What did Claude improve after you added context, format, or review criteria?',
      reject:'Reject if the submission is only a chat answer with no source context, revision, or review gate.'
    };
    if(track==='research')return {
      name:'research evidence pack',
      make:'Build a source-backed answer that separates claims, evidence, uncertainty, and final recommendation.',
      proof:'Research question, source list, claim table, verification notes, final output, and uncertainty note.',
      reflection:'Which claim needed the strongest verification before you trusted it?',
      reject:'Reject if claims have no sources, citations are not checked, or uncertainty is hidden.'
    };
    if(track==='foundations')return {
      name:'starter kit artifact',
      make:'Build a beginner-safe proof that shows the task, prompt, tool choice, result, and revision.',
      proof:'Task brief, prompt, chosen tool, first output, revised output, and one verification or quality note.',
      reflection:'What changed after you made the prompt or tool choice more specific?',
      reject:'Reject if the task is vague, the output is not visible, or the student cannot explain the tool choice.'
    };
    if(track==='signature')return {
      name:'concept production board',
      make:'Build a concept-first board with audience, emotional hook, first frame, sequence spine, and distribution note.',
      proof:'Concept brief, first-frame prompt, story spine, specimen output or storyboard, platform note, and critique.',
      reflection:'Which concept decision made the work more shareable before tool choice entered?',
      reject:'Reject if the board is only pretty visuals with no audience, emotion, or sequence logic.'
    };
    return {
      name:'prompt-output board',
      make:'Build one controlled visual board that proves the session rule through prompt, output, and decision notes.',
      proof:'Prompt/reference, generated result, controlled variable, keeper/reject note, and final recommendation.',
      reflection:'Which visual decision changed the output most clearly?',
      reject:'Reject if the images are unrelated, prompts are hidden, or the chosen keeper has no rationale.'
    };
  }
  function richHomeworkFallback(module,lesson){
    var hw=lesson.homework||{},profile=homeworkProfile(module),parts=lessonLabParts(lesson.lab||''),title=lesson.title||'Session artifact';
    var artifact=hw.deliverable||title+' '+profile.name;
    var deliverables=Array.isArray(hw.deliverables)?hw.deliverables:[
      artifact,
      'Input proof: '+(parts.starter||profile.proof),
      'Decision proof: '+(parts.constraint||'label the controlled variable and why it was chosen'),
      'Final proof: '+(parts.success||'show the output and the quality decision')
    ];
    var steps=Array.isArray(hw.steps)?hw.steps:[
      'Name the real task or brief for "'+title+'".',
      'Create the first pass using the session rule.',
      'Change one variable only and record what changed.',
      'Choose the keeper or safest workflow and write the reason.',
      'Package the proof so another student can judge it without extra explanation.'
    ];
    var checklist=Array.isArray(hw.checklist)?hw.checklist:[
      cleanSentence(parts.starter,'The starting input or brief is visible.'),
      cleanSentence(parts.constraint,'Only one controlled variable changes.'),
      cleanSentence(parts.success,'The success criteria can be checked from the output.'),
      cleanSentence(parts.failure,'The failure mode is named before submission.')
    ];
    return Object.assign({},hw,{
      deliverable:hw.deliverable||artifact,
      brief:hw.brief||profile.make+' Session focus: '+title+'.',
      deliverables:deliverables.slice(0,4),
      steps:steps.slice(0,5),
      checklist:checklist.slice(0,5),
      proofRequired:hw.proofRequired||profile.proof,
      reflection:hw.reflection||profile.reflection,
      reviewGate:hw.reviewGate||profile.reject
    });
  }
  function ensureRichHomework(modules){
    modules.forEach(function(module){
      (module.lessons||[]).forEach(function(lesson){
        var hw=lesson.homework||{};
        var rich=hw.brief&&Array.isArray(hw.deliverables)&&Array.isArray(hw.steps)&&Array.isArray(hw.checklist)&&hw.proofRequired&&hw.reflection&&hw.reviewGate;
        if(!rich)lesson.homework=richHomeworkFallback(module,lesson);
      });
    });
    return modules;
  }
  function ensureKeyInsights(modules){
    modules.forEach(function(module){
      (module.lessons||[]).forEach(function(lesson){
        if(Array.isArray(lesson.keyInsights)&&lesson.keyInsights.length)return;
        var cards=lesson.learnCards||{},parts=lessonLabParts(lesson.lab||''),mode=moduleContentMode(module);
        lesson.keyInsights=[
          {label:'Decision rule',text:cleanSentence(cards.coreIdea||lesson.title,'Name the rule before using the tool.')},
          {label:'Specimen check',text:'In See, identify the '+mode.input+', the '+mode.decision+', and the visible '+mode.output+'.'},
          {label:'Lab move',text:cleanSentence(parts.constraint||'Change one variable only, then compare against the quality bar.')},
          {label:'Avoid',text:cleanSentence(cards.mistakeToAvoid||parts.failure,'Do not submit a polished result without proof.')}
        ];
      });
    });
    return modules;
  }
