  function ensurePromptLabs(modules){
    modules.forEach(function(module){
      var packs=PROMPT_LAB_PACKS[module.id];
      if(!packs)return;
      (module.lessons||[]).forEach(function(lesson){
        if(lesson.promptLab)return;
        var pack=packs[lesson.n];
        if(pack)lesson.promptLab=pack;
      });
    });
    return modules;
  }
  function generatedPromptLab(module,lesson){
    var track=(module&&module.track)||'image',mode=moduleContentMode(module),parts=lessonLabParts(lesson&&lesson.lab);
    var title=(lesson&&lesson.title)||'Session';
    var tool=(Array.isArray(module&&module.tools)&&module.tools.length?module.tools.slice(0,2).join(' + '):'AI tool');
    function trimStop(text){
      return String(text||'').trim().replace(/[.!?]+$/,'');
    }
    var starter=trimStop(parts.starter||lesson&&lesson.studentOutcome||lesson&&lesson.teachingGoal||title);
    var constraint=trimStop(parts.constraint||('change one '+mode.decision+' only'));
    var success=trimStop(parts.success||('the '+mode.output+' proves the session decision'));
    var failure=trimStop(parts.failure||('the result looks polished but the decision is not visible'));
    var base='Session focus: '+title+'. Start with '+starter+'. Control: '+constraint+'.';
    function item(label,prompt,highlight,result,use,level){
      return labItem(label,prompt,highlight,result,use,level);
    }
    if(track==='foundations')return labPack(title+' starter prompt lab','Practice the beginner loop: task, role, context, tool choice, output, and verification.',base,tool,[
      item('Task frame','Write a one-sentence task brief for "'+title+'". Include audience, output, and what would make the result useful.','task brief','The task becomes specific enough for an AI tool to help.','Use before opening any tool.','brief'),
      item('RCTF prompt','Turn this task into an RCTF prompt: '+starter+'. Include role, context, task, and format.','role, context, task, format','Students see how structure changes the answer.','Use as the first controlled prompt.','core'),
      item('Tool decision','Choose the best tool for the task and write why it fits better than one alternative.','why it fits','Tool choice becomes a learning decision, not a habit.','Use when comparing ChatGPT, Claude, Gemini, Perplexity, or Canva.','decision'),
      item('Verification note','Add a verification note using this quality bar: '+success+'. Name what must be checked and what could be wrong.','what must be checked','The output becomes safer to trust and revise.','Use before Homework.','proof')
    ]);
    if(track==='research')return labPack(title+' research lab','Practice source-first research: question, source, claim, verification, and output.',base,tool,[
      item('Question frame','Rewrite the research task as one narrow question with audience, decision, date range, and source expectation.','one narrow question','A narrower question creates better sources and fewer hallucinations.','Use before deep research.','brief'),
      item('Source compare','Find or list three source types you would trust. Label each as official, expert, market signal, or weak reference.','official, expert, market signal','Source quality becomes visible.','Use before accepting an AI summary.','source'),
      item('Claim audit','Extract three claims from the AI answer and mark support level: strong, partial, weak, or unsupported. Failure to watch: '+failure+'.','support level','Students separate citation presence from evidence.','Use for verification.','audit'),
      item('Output pack','Turn one verified claim into a short audience-ready output with source note, implication, and next action.','source note, implication, next action','Research becomes a usable artifact, not a long report.','Use for Homework.','output')
    ]);
    if(track==='video')return labPack(title+' video prompt lab','Practice video control through one shot decision, one motion variable, one repair, and one proof board.',base,tool,[
      item('Shot baseline','Write a 5-8 second shot prompt for "'+title+'": subject, setting, shot type, camera state, subject motion, and end frame.','shot type, camera state, subject motion','The first clip has a readable structure.','Use before adding style or effects.','baseline'),
      item('Motion variant','Rewrite the prompt changing only this control: '+constraint+'. If needed, narrow it to one camera move, actor action, physics behavior, pacing change, or audio cue.','one motion variable','The comparison teaches cause and effect.','Use for the Lab run.','control'),
      item('Repair pass','Diagnose the weakest output. Repair only the named failure: jitter, drift, physics, timing, lip sync, or export issue.','Repair only the named failure','Students stop regenerating randomly.','Use after the first output.','repair'),
      item('Proof board','Package the shot prompt, reference/keyframe, output screenshot, failure note, and keeper decision in one board.','keeper decision','The final clip can be reviewed without guessing.','Use for Homework.','proof')
    ]);
    if(track==='automation'||track==='operations')return labPack(title+' workflow lab','Practice safe automation through input, AI draft, approval gate, run receipt, and rollback.',base,tool,[
      item('Manual map','Map the current manual workflow for "'+title+'": input, owner, AI step, approval point, final output, and failure path.','input, owner, AI step','The workflow starts with real boundaries.','Use before building automation.','map'),
      item('AI draft','Write the prompt or automation instruction that turns the source input into a draft output without sending, paying, publishing, or promising.','draft output','AI is allowed to prepare, not act unsafely.','Use for the first run.','draft'),
      item('Approval gate','Add a human approval gate with criteria: what passes, what gets edited, what must stop, who approves, and how to prove: '+success+'.','human approval gate','Students learn safe production automation.','Use before connecting actions.','gate'),
      item('Run receipt','Create a run receipt: input sample, output sample, approval status, error case, and next improvement.','run receipt','The automation can be audited and taught.','Use for Homework.','proof')
    ]);
    if(track==='claude')return labPack(title+' Claude workbench lab','Practice Claude as a context-to-artifact workbench: brief, context, first draft, critique, revision, reusable asset.',base,tool,[
      item('Context pack','Paste or summarize the source context for "'+title+'": goal, audience, constraints, examples, and forbidden assumptions.','source context','Claude works better when the context is explicit.','Use before the first prompt.','context'),
      item('Artifact prompt','Ask Claude for one named artifact with format, quality criteria, and review owner. Use this control: '+constraint+'.','one named artifact','The output becomes usable work.','Use for the main run.','artifact'),
      item('Critique pass','Run a critique prompt against the output: missing context, risk, weak wording, unsupported claim, or wrong format.','critique prompt','Students learn to review Claude, not accept it.','Use after the first draft.','review'),
      item('Reusable version','Turn the improved output into a reusable template, skill, checklist, or workflow note with placeholders.','reusable template','The work becomes a system, not one chat.','Use for Homework.','system')
    ]);
    if(track==='signature')return labPack(title+' concept lab','Practice concept-first production: audience, emotional hook, first frame, sequence spine, and distribution proof.',base,tool,[
      item('Audience hook','Define the audience and emotional hook before choosing a tool. Write why this concept should make someone stop.','audience and emotional hook','The idea leads the production.','Use before prompts.','concept'),
      item('First frame','Write a first-frame prompt that makes the concept clear in one still image or opening shot.','first-frame prompt','The opening frame becomes the anchor.','Use for visual direction.','frame'),
      item('Sequence spine','Build a 3-5 beat spine: open, tension, turn, proof, close. Keep every beat tied to the same concept.','3-5 beat spine','The piece becomes a sequence instead of random visuals.','Use for story planning.','sequence'),
      item('Distribution proof','Write the platform fit, caption angle, thumbnail idea, and one reason the concept could spread.','platform fit','Publishing logic becomes part of the assignment.','Use for Homework.','distribution')
    ]);
    return labPack(title+' image prompt lab','Practice visual control through prompt, reference, output, comparison, and keeper decision.',base,tool,[
      item('Baseline prompt','Generate the first version for "'+title+'". Keep the subject simple and make the prompt visible.','prompt visible','The baseline shows what the tool does before control.','Use first.','baseline'),
      item('Controlled variant','Rewrite the prompt changing only this control: '+constraint+'. Keep the subject, crop, and palette stable unless the lesson asks otherwise.','changing only '+mode.decision,'One visible change creates a useful comparison.','Use for the main Lab test.','control'),
      item('Failure repair','Name the likely failure: drift, fake text, weak composition, wrong crop, bad lighting, or unclear reference. Repair only that failure.','Repair only that failure','The repair prompt teaches diagnosis.','Use after the first output.','repair'),
      item('Specimen board','Package prompt, reference if used, output, what changed, why it worked, and what to reject next time.','what changed, why it worked','The final image becomes a teachable specimen.','Use for Homework.','proof')
    ]);
  }
  function ensureUniversalPromptLabs(modules){
    modules.forEach(function(module){
      (module.lessons||[]).forEach(function(lesson){
        if(!lesson.promptLab)lesson.promptLab=generatedPromptLab(module,lesson);
      });
    });
    return modules;
  }
  function finalizeLearningContent(modules){
    if(!Array.isArray(modules))return modules;
    return ensureUniversalPromptLabs(ensurePromptLabs(ensureKeyInsights(ensureRichHomework(ensureLessonSpecimens(modules)))));
  }
